class Solution:
    def minimumPossibleSum(self, n, target):
        MOD = 10 ** 9 + 7
        low_count = target // 2
        if n <= low_count:
            return (n * (n + 1) // 2) % MOD
        r = n - low_count
        total = low_count * (low_count + 1) // 2 + r * target + r * (r - 1) // 2
        return total % MOD

