var minimumPossibleSum = function(n, target) {
    const MOD = 1000000007n;
    const N = BigInt(n), T = BigInt(target);
    const lowCount = T / 2n;
    if (N <= lowCount) {
        return Number((N * (N + 1n) / 2n) % MOD);
    }
    const r = N - lowCount;
    let total = (lowCount * (lowCount + 1n)) / 2n;
    total += r * T;
    total += (r * (r - 1n)) / 2n;
    return Number(total % MOD);
};
